SELECT item_name 
FROM clothing_items 
WHERE gender = 'Male' AND season = 'Summer';

SELECT *
FROM sizing_standards
WHERE expiration_date < CURRENT_DATE;

SELECT ci.item_name, ci.description, cic.category_name
FROM clothing_items ci
LEFT JOIN clothing_item_categories cic ON ci.category_id = cic.category_id;

SELECT COUNT(*)
FROM sizing_standards
WHERE item_id = 1;
